def fn():
    diff = 0
    ans = 0
    f = 'p'
    n = int(input())
    s = input()
    if len(s) % 2 == 1:
        return -1

    for i in range(n):
        if s[i] == '(': diff += 1
        elif s[i] == ')': diff -= 1

        if diff >= 0:
            f = 'p'
            continue

        elif diff < 0:
            ans += 1
            if f == 'p':
                f = 'n'
                ans +=1
    if diff == 0:
        return ans
    else:
        return -1

