def main():
    n, m = map(int, input().split())
    if abs(n - m) > 1:
        return 0


    fact = 1
    for i in range(1, min(n, m) + 1):
        fact = fact * i % mod



    if n == m:
        return fact ** 2 * 2 % mod
    else:
        return fact * fact * (min(n, m) + 1) % mod




