else:
    Dict = {}
    for x in l:
        try:
            Dict[x] += 1
        except KeyError:
            Dict[x] = 1
    cnt, book =0, {}
    for x in l:
        if book.__contains__(x) :
            continue
        flag = False
        t = 1 << 30
        while t >= 1:
            if  t <= x:
                break
            if 2 * x == t and Dict[x] == 1:
                t >>= 1
                continue
            if Dict.__contains__(t - x):
                flag , book[x], book[t-x] = True, True, True
                break
            t >>= 1
        if not flag:
            cnt += 1
    print(cnt)

