def get_res(a, b, c, d):
    if a==0 or b==0 or c==0:
        l = [x%2 for x in [a,b,c,d]]
        odds = sum(l)
        if odds > 1:
            return 'No'
        else:
            return 'Yes'
    else:
        l = [x%2 for x in [a,b,c,d]]
        odds = sum(l)
        if odds == 2:
            return 'No'
        else:
            return 'Yes'


