import math

def BearAndBigBrother():
    a, b = map(int, input().split(' '))
    year = 0
    while 1:
        if a > b:
            break
        else:
            a *= 3
            b *= 2
            year += 1
    print(year)
    return None

def Tram():
    n = int(input())
    p = [0]
    for i in range(1, n+1):
        a, b = map(int, input().split())
        tmp = p[i-1]
        tmp -= a
        tmp += b
        p.append(tmp)
    print(max(p))
    return None


def WrongSubtraction():
    n ,k = map(int, input().split())
    for i in range(k):
        if n % 10 == 0:
            n = n // 10
        else:
            n -= 1
    print(n)
    return None


def Elephant():
    x = int(input())
    i = steps = 0
    tmp = [j for j in range(1, 6) if x // j > 0]
    stepsize = max(tmp)
    while i < x:
        steps += (x-i) // stepsize
        i += stepsize*steps
        tmp2 = [j for j in range(1, stepsize) if (x-i) // j > 0]
        try:
            stepsize = max(tmp2)
        except:
            continue
    print(steps)

    return None


def QueueAtTheSchool():
    n, t = map(int, input().split())
    s = input()
    Q = [i for i in s]
    for i in range(t):
        j = 0
        while j < len(Q)-1:
            if Q[j] == 'B' and Q[j+1] == 'G':
                Q[j], Q[j+1] = Q[j+1], Q[j]
                j += 2
            else:
                j += 1
    s_f = ''.join(Q)
    print(s_f)

    return None


