import math


def solve(n):
    p = 1
    for i in range(2, int(math.ceil(math.sqrt(n)))+1):
        if n % i == 0:
            p = i
            break
    if p != 1:
        k = n//p
    else:
        k = 1
    return " ".join([str(k), str(n - k)])


def read():
    t = int(input())
    for i in range(t):
        n = int(input())
        ans = solve(n)
        print(ans)

