def factors(n):
    i = 1
    while i * i <= n:
        if n % i == 0:
            yield i
            yield n // i
        i += 1

for t in range(int(input())):
    n = int(input())
    s = sorted(list(factors(n)))[-2]
    print(s, n - s)

