def solution(n,s):
	ans = [" "]*n

	if n%2==0:
		p = int(n/2) - 1
		for i in range(n):
			if i%2==0:
				ans[p - int(i/2) ] = s[i]
			else:
				ans[p + int((i+1)/2) ] = s[i]
	else:
		p = int(n/2)
		for i in range(n):
			if i%2==0:
				ans[p + int(i/2) ] = s[i]
			else:
				ans[p - int((i+1)/2) ] = s[i]	
	return ''.join(ans)

