def helper(s):
    if s[0]==s[-1]:
        print('NO')
        return
    a=[]
    start=s[0]
    end=s[-1]
    flag=0
    for i in s:
        if i==start:
            a.append('(')
        elif i==end:
            if len(a)==0:
                flag=1
                break
            a.pop()
        else:
            a.append('(')
    if len(a)==0 and flag==0:
        print('YES')
        return
    a=[]
    for i in s:
        if i==s[0]:
            a.append('(')
        elif i==end:
            if len(a)==0:
                print('NO')
                return
            a.pop()
        else:
            if len(a)==0:
                print('NO')
                return
            a.pop()
    if len(a)==0:
        print('YES')
    else:
        print("NO")


