n=int(input())
arr=list(map(int,input().split()))
def solve(arr,bit):
    if len(arr)==0 or bit <0:
        return 0
    l=[]
    r=[]
    for i in arr:
        if (i>>bit)&1==0:
            l.append(i)
        else:
            r.append(i)


    if len(l)==0:
        return solve(r,bit-1)

    if len(r)==0:
        return solve(l,bit-1)

    return min(solve(r,bit-1),solve(l,bit-1))+(1<<bit)
print(solve(arr,30))

n = int(input())
seq = sorted(list(map(int, input().split())))

#Left (inc), Right(exc), bit to check, value to add 
queue = [(0,n,30,0)]
best = 2 ** 30
while queue:
    l, r, b, v = queue.pop()
    if b >= 0:
        mask = 1 << b

        if not mask & seq[l] and mask & seq[r - 1]:
            for i in range(l, r):
                if mask & seq[i]:
                    queue.append((l,i,b - 1, v + mask))
                    queue.append((i,r,b - 1, v + mask))
                    break
        else:
            queue.append((l, r, b - 1, v))
    else:
        best = min(best, v)

print(best)

